function truncateName(e,t=15){return e.length>t?e.slice(0,t-3)+"...":e}firebase.auth().onAuthStateChanged((e=>{if(e=firebase.auth().currentUser){var t=document.getElementById("login-signup"),n=document.getElementById("loggedin-tools"),a=document.getElementById("userDisplayName"),s=document.getElementById("userProfileImage"),m=document.getElementById("adminLink"),o=document.getElementById("userDisplayNameWelcome");t.classList.add("d-none"),n.classList.remove("d-none"),a.innerText=e.displayName,s.src=e.photoURL,firebase.firestore().collection("users").doc(e.uid).get().then((e=>{if(e.exists){"admin"==e.data().role?m.classList.remove("d-none"):document.getElementsByClassName("admin")[0].remove();const t=e.data().firstname;o.innerText=truncateName(t)+"!"}}))}}));